import { useEffect, useState, useContext } from "react";
import { AuthContext } from "./AuthContext";

import EventHeader from "./EventHeader";


export default function EventPage() {
    const { user } = useContext(AuthContext);
    const [event, setEvent] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");

    const [rsvp, setRsvp] = useState(null);
    const [counts, setCounts] = useState({ going: 0, maybe: 0 });

    const [showAttendees, setShowAttendees] = useState(false);
    const [attendeeStatus, setAttendeeStatus] = useState("GOING"); // GOING | MAYBE
    const [attendees, setAttendees] = useState([]);
    const [attendeesLoading, setAttendeesLoading] = useState(false);


    const eventId = (() => {
        const m = (window.location.hash || "").match(/^#\/events\/(\d+)/);
        return m ? Number(m[1]) : null;
    })();

    useEffect(() => {
        if (!eventId || !user) return;

        fetch(`/api/events/${eventId}/rsvp?requesterEmail=${encodeURIComponent(user.email)}`)
            .then(r => r.json())
            .then(data => setRsvp(data.status || null))
            .catch(() => {});
    }, [eventId, user]);


    const sendRSVP = async (status) => {
        if (!user) {
            alert("Please log in to RSVP");
            return;
        }

        await fetch(
            `/api/events/${eventId}/rsvp?requesterEmail=${encodeURIComponent(user.email)}&status=${status}`,
            { method: "POST" }
        );

        setRsvp(status);

        // refresh counts
        const c = await fetch(`/api/events/${eventId}/attendance`).then(r => r.json());
        setCounts(c);
    };

    useEffect(() => {
        if (!eventId) return;

        fetch(`/api/events/${eventId}`)
            .then(res => {
                if (!res.ok) throw new Error("Event not found");
                return res.json();
            })
            .then(setEvent)
            .catch(err => setError(err.message))
            .finally(() => setLoading(false));
    }, [eventId]);

    if (loading) {
        return <div style={styles.page}>Loading event…</div>;
    }

    if (error || !event) {
        return <div style={styles.page}>{error || "Event not found"}</div>;
    }

    const start = event.startAt ? new Date(event.startAt) : null;
    const end = event.endAt ? new Date(event.endAt) : null;

    const cancelRSVP = async () => {
        await fetch(
            `/api/events/${eventId}/rsvp?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "DELETE" }
        );

        setRsvp(null);

        const c = await fetch(`/api/events/${eventId}/attendance`).then(r => r.json());
        setCounts(c);
    };

    const openAttendees = async (status) => {
        setAttendeeStatus(status);
        setShowAttendees(true);
        setAttendees([]);
        setAttendeesLoading(true);

        try {
            const data = await fetch(`/api/events/${eventId}/attendees?status=${status}`)
                .then(r => {
                    if (!r.ok) throw new Error("Failed to load attendees");
                    return r.json();
                });

            setAttendees(Array.isArray(data) ? data : []);
        } catch {
            setAttendees([]);
        } finally {
            setAttendeesLoading(false);
        }
    };



    return (
        <main style={styles.page}>
            <EventHeader
                event={event}
                activeTab="overview"
                rsvp={rsvp}
                onRSVP={sendRSVP}
                onCancelRSVP={cancelRSVP}
            />

            <div style={styles.card}>
                <button
                    style={styles.back}
                    onClick={() => (window.location.hash = "#/")}
                >
                    ← Back
                </button>

                <h1 style={styles.title}>{event.title}</h1>

                {(start || end) && (
                    <div style={styles.time}>
                        {start && <div><strong>Starts:</strong> {start.toLocaleString()}</div>}
                        {end && <div><strong>Ends:</strong> {end.toLocaleString()}</div>}
                    </div>
                )}

                {event.location && (
                    <div style={styles.section}>
                        <strong>Location:</strong> {event.location}
                    </div>
                )}

                {event.description && (
                    <div style={styles.section}>
                        {event.description}
                    </div>
                )}
                {/* Future extensions */}
                {/* RSVP button */}
                <div style={styles.attendeeLinks}>
                    <button style={styles.linkBtn} onClick={() => openAttendees("GOING")}>
                        View Going ({counts.going})
                    </button>
                    <button style={styles.linkBtn} onClick={() => openAttendees("MAYBE")}>
                        View Maybe ({counts.maybe})
                    </button>
                </div>


                <div style={styles.rsvpRow}>
                    <button
                        style={rsvp === "GOING" ? styles.rsvpActive : styles.rsvpBtn}
                        onClick={() => rsvp === "GOING" ? cancelRSVP() : sendRSVP("GOING")}
                    >
                        {rsvp === "GOING" ? "Cancel Going" : `Going (${counts.going})`}
                    </button>

                    <button
                        style={rsvp === "MAYBE" ? styles.rsvpActive : styles.rsvpBtn}
                        onClick={() => rsvp === "MAYBE" ? cancelRSVP() : sendRSVP("MAYBE")}
                    >
                        {rsvp === "MAYBE" ? "Cancel Maybe" : `Maybe (${counts.maybe})`}
                    </button>
                </div>
                {showAttendees && (
                    <div style={styles.modalBackdrop} onClick={() => setShowAttendees(false)}>
                        <div style={styles.modalCard} onClick={(e) => e.stopPropagation()}>
                            <div style={styles.modalHeader}>
                                <h3 style={{ margin: 0 }}>
                                    {attendeeStatus === "GOING" ? "Going" : "Maybe"} Attendees
                                </h3>
                                <button style={styles.modalClose} onClick={() => setShowAttendees(false)}>
                                    ✕
                                </button>
                            </div>

                            <div style={styles.modalTabs}>
                                <button
                                    style={attendeeStatus === "GOING" ? styles.tabActive : styles.tab}
                                    onClick={() => openAttendees("GOING")}
                                >
                                    Going
                                </button>
                                <button
                                    style={attendeeStatus === "MAYBE" ? styles.tabActive : styles.tab}
                                    onClick={() => openAttendees("MAYBE")}
                                >
                                    Maybe
                                </button>
                            </div>

                            <div style={styles.modalBody}>
                                {attendeesLoading ? (
                                    <div style={styles.muted}>Loading…</div>
                                ) : attendees.length === 0 ? (
                                    <div style={styles.muted}>No attendees yet.</div>
                                ) : (
                                    attendees.map(a => (
                                        <div key={a.id} style={styles.attendeeRow}>
                                            <div style={styles.attendeeAvatar}>
                                                {String(a.username || "?").slice(0, 1).toUpperCase()}
                                            </div>
                                            <div style={{ minWidth: 0 }}>
                                                <div style={styles.attendeeName}>{a.username}</div>
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    </div>
                )}


                {/* Event posts */}

                {/* Comments */}
            </div>
        </main>
    );
}



const styles = {
    page: {
        minHeight: "100vh",
        background: "#2f2f2f",
        display: "flex",
        justifyContent: "center",
        padding: "40px 16px"
    },
    card: {
        width: "100%",
        maxWidth: 700,
        background: "#4a4a4a",
        color: "#FFFFE3",
        borderRadius: 8,
        padding: 24,
        boxShadow: "0 10px 25px rgba(0,0,0,0.3)"
    },
